class Solution {
    public int maxScoreSightseeingPair(int[] values) {
        int maxScore = Integer.MIN_VALUE;
        int mx = values[0] + 0;
        for (int j = 1; j < values.length; j++) {
            maxScore = Math.max(maxScore, mx + values[j] - j);
            mx = Math.max(mx, values[j] + j);
        }
        return maxScore;
    }
}
